{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯的拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi de ná tiě, kě yǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de5 na2 tie3, ke3 yi3 ma0?",
      "translation_en": "Hello, I would like a small latte, okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "可以幫我加珍珠嗎？",
      "pinyin": "Kě yǐ bāng wǒ jiā zhēn zhū ma?",
      "pinyin_numeric": "ke3 yi3 bang1 wo3 jia1 zhen1 zhu1 ma0?",
      "translation_en": "Can you add boba for me?",
      "translation_ko": "타피오카 펄을 추가해 주시겠어요?"
    },
    {
      "text": "我想要一杯冰的紅茶，少冰，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi bīng de hóng chá, shǎo bīng, kě yǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 bing1 de5 hong2 cha2, shao3 bing1, ke3 yi3 ma0?",
      "translation_en": "I would like an iced black tea with less ice, okay?",
      "translation_ko": "얼음 적게 넣은 아이스 홍차 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "麻煩給我一個袋子，可以嗎？",
      "pinyin": "Má fan gěi wǒ yī gè dài zi, kě yǐ ma?",
      "pinyin_numeric": "ma2 fan5 gei3 wo3 yi1 ge4 dai4 zi5, ke3 yi3 ma0?",
      "translation_en": "Could you please give me a bag?",
      "translation_ko": "봉투 하나 주시겠어요?"
    },
    {
      "text": "可以給我一根吸管嗎？",
      "pinyin": "Kě yǐ gěi wǒ yī gēn xī guǎn ma?",
      "pinyin_numeric": "ke3 yi3 gei3 wo3 yi1 gen1 xi1 guan3 ma0?",
      "translation_en": "Can you give me a straw?",
      "translation_ko": "빨대 하나 주시겠어요?"
    },
    {
      "text": "我想要一杯中杯的豆漿，半糖，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi zhōng bēi de dòu jiāng, bàn táng, kě yǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 zhong1 bei1 de5 dou4 jiang1, ban4 tang2, ke3 yi3 ma0?",
      "translation_en": "I would like a medium soy milk with half sugar, okay?",
      "translation_ko": "중간 컵 두유 반 당을 원하는데 괜찮을까요?"
    },
    {
      "text": "可以幫我外帶嗎？",
      "pinyin": "Kě yǐ bāng wǒ wài dài ma?",
      "pinyin_numeric": "ke3 yi3 bang1 wo3 wai4 dai4 ma0?",
      "translation_en": "Can you make it for takeout?",
      "translation_ko": "포장해 주시겠어요?"
    },
    {
      "text": "不好意思，可以再說一次嗎？",
      "pinyin": "Bù hǎo yì si, kě yǐ zài shuō yī cì ma?",
      "pinyin_numeric": "bu4 hao3 yi4 si5, ke3 yi3 zai4 shuo1 yi1 ci4 ma0?",
      "translation_en": "Excuse me, can you say that again?",
      "translation_ko": "죄송합니다만, 한 번 더 말씀해 주시겠어요?"
    },
    {
      "text": "可以請你慢一點說嗎？",
      "pinyin": "Kě yǐ qǐng nǐ màn yī diǎn shuō ma?",
      "pinyin_numeric": "ke3 yi3 qing3 ni3 man4 yi1 dian3 shuo1 ma0?",
      "translation_en": "Can you please speak a bit slower?",
      "translation_ko": "조금 천천히 말씀해 주시겠어요?"
    },
    {
      "text": "我想要一杯大杯的綠茶，去冰，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi dà bēi de lǜ chá, qù bīng, kě yǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 da4 bei1 de5 lv4 cha2, qu4 bing1, ke3 yi3 ma0?",
      "translation_en": "I would like a large green tea with no ice, okay?",
      "translation_ko": "얼음 없는 큰 녹차 한 잔을 원하는데 괜찮을까요?"
    }
  ]
}
